import React, { useState, useEffect, useRef } from 'react';
import {
  CheckCircle,
  Award,
  Users,
  TrendingUp,
  ChevronLeft,
  ChevronRight,
} from 'lucide-react';
import './AboutUsPage.css';

const campusData = {
  depok: [
    { src: '/facilities/depok1.jpeg', title: 'Robotics Lab D', desc: 'Lab robotika kampus Depok' },
    { src: '/facilities/depok2.jpeg', title: 'Electronics D', desc: 'Lab elektronik lengkap' },
  ],
  kalimalang: [
    { src: '/facilities/j1.jpeg', title: 'IoT Lab J', desc: 'Zona IoT Kalimalang' },
    { src: '/facilities/j2.jpeg', title: 'AI Lab J', desc: 'AI & ML Lab' },
  ],
  karawaci: [
    { src: '/facilities/k1.jpeg', title: 'Multimedia Lab K', desc: 'Studio multimedia' },
    { src: '/facilities/k2.jpeg', title: '3D Printing K', desc: 'Rapid prototyping' },
  ],
};

const teamStructure = {
  director: {
    name: 'Dr. Sarah Chen',
    role: 'Director',
    emoji: '👩‍🔬',
  },
  members: [
    { name: 'Mike', role: 'Research Engineer', emoji: '👨‍💼' },
    { name: 'Emma', role: 'RnD Lab Technician', emoji: '👩‍🏫' },
    { name: 'James', role: 'Practice Lab Technician', emoji: '👨‍🔬' },
    { name: 'Alex', role: 'Practice Lab Technician', emoji: '👨‍🔧' },
  ],
};

function FacilitySlider({ slides }) {
  const [current, setCurrent] = useState(0);
  const autoRef = useRef(null);

  const resetAuto = () => {
    clearInterval(autoRef.current);
    autoRef.current = setInterval(() => {
      setCurrent((prev) => (prev + 1) % slides.length);
    }, 4000);
  };

  useEffect(() => {
    clearInterval(autoRef.current);
    autoRef.current = setInterval(() => {
      setCurrent(prev => (prev + 1) % slides.length);
    }, 4000);

    return () => clearInterval(autoRef.current);
    }, [slides.length]);

  const prev = () => {
    setCurrent((prev) => (prev - 1 + slides.length) % slides.length);
    resetAuto();
  };

  const next = () => {
    setCurrent((prev) => (prev + 1) % slides.length);
    resetAuto();
  };

  return (
    <div className="facility-slider ios-slider">
      {slides.map((slide, i) => (
        <div
          key={i}
          className={`facility-slide ${i === current ? 'active' : ''}`}
        >
          <img src={slide.src} alt={slide.title} />
          <div className="facility-slide-overlay">
            <h4>{slide.title}</h4>
            <p>{slide.desc}</p>
          </div>
        </div>
      ))}

      <button className="facility-btn facility-btn-prev" onClick={prev}>
        <ChevronLeft size={20} />
      </button>
      <button className="facility-btn facility-btn-next" onClick={next}>
        <ChevronRight size={20} />
      </button>
    </div>
  );
}

export default function AboutUsPage() {
  const [activeCampus, setActiveCampus] = useState('depok');

  return (
    <>
      <section className="page-header">
        <div className="container">
          <h1>Tentang Kami</h1>
          <p>Modern Lab with Multi Campus Facilities</p>
        </div>
      </section>

      <section className="aboutus-section">
        <div className="container">
          <div className="facilities-section">
            <h2 className="facilities-title">Fasilitas</h2>

            {/* BUTTON CAMPUS */}
            <div className="campus-tabs">
              <button
                className={activeCampus === 'depok' ? 'active' : ''}
                onClick={() => setActiveCampus('depok')}
              >
                Kampus Depok (D)
              </button>

              <button
                className={activeCampus === 'kalimalang' ? 'active' : ''}
                onClick={() => setActiveCampus('kalimalang')}
              >
                Kampus Kalimalang (J)
              </button>

              <button
                className={activeCampus === 'karawaci' ? 'active' : ''}
                onClick={() => setActiveCampus('karawaci')}
              >
                Kampus Karawaci (K)
              </button>
            </div>

            <FacilitySlider slides={campusData[activeCampus]} />
          </div>

          <div className="team-section">
            <h2>Our Team</h2>

            {/* DIRECTOR */}
            <div className="team-director">
              <div className="team-avatar large">
                {teamStructure.director.emoji}
              </div>
              <h3>{teamStructure.director.name}</h3>
              <p>{teamStructure.director.role}</p>
            </div>

            {/* MEMBERS */}
            <div className="team-grid">
              {teamStructure.members.map((m, i) => (
                <div key={i} className="team-card">
                  <div className="team-avatar">{m.emoji}</div>
                  <h4>{m.name}</h4>
                  <p>{m.role}</p>
                </div>
              ))}
            </div>
          </div>

        </div>
      </section>
    </>
  );
}
